class FreqStack {
public:
    FreqStack() {

    }

    void push(int val) {
        count[val]++;
        freq[ count[val] ].push(val);
        max_freq = max(max_freq, count[val]);
    }

    int pop() {
        int val = freq[max_freq].back();
        freq[max_freq].pop_back();
        count[val]--;
        if (freq[max_freq].empty()) max_freq--;
        return val;
    }
private:
    unordered_map<int, int> count;
    unordered_map<int, stack<int>> freq;
    int max_freq = 0;
};

